import{_ as a,o as t,c as i,ag as o}from"./chunks/framework.CvgP6Fyv.js";const p=JSON.parse('{"title":"Email Logging","description":"","frontmatter":{},"headers":[],"relativePath":"features/email-logging.md","filePath":"features/email-logging.md"}'),r={name:"features/email-logging.md"};function l(n,e,s,d,c,g){return t(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="email-logging" tabindex="-1">Email Logging <a class="header-anchor" href="#email-logging" aria-label="Permalink to &quot;Email Logging&quot;">​</a></h1><p>SendGrail logs every outgoing email with detailed metadata, delivery status, and optional body content. The email log provides a comprehensive audit trail for troubleshooting and monitoring.</p><h2 id="logged-fields" tabindex="-1">Logged Fields <a class="header-anchor" href="#logged-fields" aria-label="Permalink to &quot;Logged Fields&quot;">​</a></h2><p>Every email captured by SendGrail records the following information:</p><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td><strong>Recipients</strong></td><td>All To, CC, and BCC addresses</td></tr><tr><td><strong>Sender</strong></td><td>From email and display name</td></tr><tr><td><strong>Subject</strong></td><td>Email subject line</td></tr><tr><td><strong>Body</strong></td><td>Full email body (when body storage is enabled)</td></tr><tr><td><strong>Headers</strong></td><td>All email headers</td></tr><tr><td><strong>Attachments</strong></td><td>List of attached files</td></tr><tr><td><strong>Status</strong></td><td>Delivery result: <code>sent</code> or <code>failed</code></td></tr><tr><td><strong>SMTP Response</strong></td><td>Raw response from the mail server</td></tr><tr><td><strong>Error</strong></td><td>Error message if delivery failed</td></tr></tbody></table><h2 id="filtering-and-search" tabindex="-1">Filtering and Search <a class="header-anchor" href="#filtering-and-search" aria-label="Permalink to &quot;Filtering and Search&quot;">​</a></h2><p>The email log supports several filtering options to help you find specific emails:</p><ul><li><strong>Status filter</strong> -- Filter by <code>sent</code> or <code>failed</code> status</li><li><strong>Search</strong> -- Search across recipient email addresses and subject lines</li><li><strong>Date range</strong> -- Filter by a custom start and end date</li></ul><p>Results are paginated at <strong>20 emails per page</strong>.</p><h2 id="email-report-view" tabindex="-1">Email Report View <a class="header-anchor" href="#email-report-view" aria-label="Permalink to &quot;Email Report View&quot;">​</a></h2><p>Clicking on an individual email opens a detailed report with the following sections:</p><h3 id="metadata" tabindex="-1">Metadata <a class="header-anchor" href="#metadata" aria-label="Permalink to &quot;Metadata&quot;">​</a></h3><p>Displays the sender, recipients, subject, timestamp, connection used, and all headers.</p><h3 id="delivery-status" tabindex="-1">Delivery Status <a class="header-anchor" href="#delivery-status" aria-label="Permalink to &quot;Delivery Status&quot;">​</a></h3><p>Shows the final delivery status along with the raw SMTP response code and message.</p><h3 id="open-tracking-card" tabindex="-1">Open Tracking Card <a class="header-anchor" href="#open-tracking-card" aria-label="Permalink to &quot;Open Tracking Card&quot;">​</a></h3><p>When <a href="/features/open-tracking">open tracking</a> is enabled, displays the open count and first-opened timestamp.</p><h3 id="click-tracking-card" tabindex="-1">Click Tracking Card <a class="header-anchor" href="#click-tracking-card" aria-label="Permalink to &quot;Click Tracking Card&quot;">​</a></h3><p>When <a href="/features/click-tracking">click tracking</a> is enabled, displays the click count, first-clicked timestamp, and the list of clicked URLs.</p><h3 id="event-timeline" tabindex="-1">Event Timeline <a class="header-anchor" href="#event-timeline" aria-label="Permalink to &quot;Event Timeline&quot;">​</a></h3><p>A chronological list of all events associated with the email: sent, opened, clicked, with timestamps and metadata.</p><h3 id="email-body-preview" tabindex="-1">Email Body Preview <a class="header-anchor" href="#email-body-preview" aria-label="Permalink to &quot;Email Body Preview&quot;">​</a></h3><p>The original email body rendered in a sandboxed iframe for safe viewing. This section only appears when body storage is enabled and the email body was captured.</p><h2 id="retention-policy" tabindex="-1">Retention Policy <a class="header-anchor" href="#retention-policy" aria-label="Permalink to &quot;Retention Policy&quot;">​</a></h2><p>Email logs can be automatically cleaned up based on a configurable retention period.</p><ul><li><strong>Range</strong>: 0 to 365 days</li><li><strong>Cleanup</strong>: A daily WordPress cron job removes logs older than the configured retention period</li><li><strong>Setting 0 days</strong>: Disables automatic cleanup, retaining logs indefinitely</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Set a reasonable retention period to manage database size. For most sites, 30 to 90 days provides a good balance between auditability and storage.</p></div><h2 id="bulk-operations" tabindex="-1">Bulk Operations <a class="header-anchor" href="#bulk-operations" aria-label="Permalink to &quot;Bulk Operations&quot;">​</a></h2><ul><li><strong>Bulk Delete</strong> -- Select multiple log entries and delete them in a single action</li><li><strong>Clear All</strong> -- Remove all email logs at once</li></ul><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Deleted email logs cannot be recovered. Use bulk delete and clear all with caution.</p></div><h2 id="body-storage" tabindex="-1">Body Storage <a class="header-anchor" href="#body-storage" aria-label="Permalink to &quot;Body Storage&quot;">​</a></h2><p>By default, email body storage is <strong>disabled</strong> to protect user privacy and reduce database usage. When disabled, all email metadata is still logged, but the body content is omitted.</p><p>To enable body storage, toggle the <strong>Store Email Body</strong> setting in the plugin settings page.</p><div class="warning custom-block"><p class="custom-block-title">Privacy Notice</p><p>Email bodies may contain sensitive information such as password reset links, personal data, or confidential content. Only enable body storage if your use case requires it and you have appropriate data handling policies in place.</p></div>',34)])])}const m=a(r,[["render",l]]);export{p as __pageData,m as default};
